   135	uint32_t to_earfcn(int eutra_bandP, uint32_t dl_CarrierFreq, uint32_t bw) {
   136	  uint32_t dl_CarrierFreq_by_100k = dl_CarrierFreq / 100000;
   137	  int bw_by_100 = bw / 100;
   138	  int i;
   139	  AssertFatal(eutra_bandP < 74, "eutra_band %d > 74\n", eutra_bandP);
   140	
   141	  for (i = 0; i < BANDTABLE_SIZE && eutra_bandtable[i].band != eutra_bandP; i++);
   142	
   143	  AssertFatal(i < BANDTABLE_SIZE, "i %d >= BANDTABLE_SIZE %ld\n", i, BANDTABLE_SIZE);
   144	  AssertFatal(eutra_bandP != 64, "LTE b64 is a reserved band");
   145	  AssertFatal(dl_CarrierFreq_by_100k >= eutra_bandtable[i].dl_min,
   146	              "Band %d, bw %u : DL carrier frequency %u Hz < %u\n",
   147	              eutra_bandP, bw, dl_CarrierFreq,
   148	              eutra_bandtable[i].dl_min);
   149	  AssertFatal(dl_CarrierFreq_by_100k <=
   150	              (eutra_bandtable[i].dl_max - bw_by_100),
   151	              "Band %d, bw %u: DL carrier frequency %u Hz > %d\n",
   152	              eutra_bandP, bw, dl_CarrierFreq,
   153	              eutra_bandtable[i].dl_max - bw_by_100);
   154	  return (dl_CarrierFreq_by_100k - eutra_bandtable[i].dl_min +
   155	          (eutra_bandtable[i].N_OFFs_DL / 10));
   156	  }
